# ==================================================================
#   MODBUS COMPATIBILITY WRAPPER
#   pymodbus <=3.6 uses slave=, >=3.7 uses device_id=
# ==================================================================
def _unit_kwarg(func):
    try:
        params = inspect.signature(func).parameters
    except (TypeError, ValueError):
        return "slave"
    if "device_id" in params:
        return "device_id"
    return "slave"


class ModbusLink:
    """Thin, thread-safe wrapper around a ModbusSerialClient."""

    def __init__(self):
        self.client = None
        self._tcp_sock = None
        self.address = 2
        self.lock = threading.Lock()
        self._read_kw = "slave"
        self._write_kw = "slave"
        self.mode = "serial"   # "serial" or "tcp"

    @property
    def connected(self):
        if self.mode == "tcp":
            return self._tcp_sock is not None
        return self.client is not None and getattr(self.client, "connected", False)

    def connect(self, port, baud, address, timeout=1):
        """Connect over serial (USB / RS485 RTU)."""
        self.disconnect()
        if not _PYMODBUS_OK:
            raise RuntimeError("pymodbus not installed - run: pip install pymodbus")
        self.mode = "serial"
        self.client = ModbusSerialClient(
            port=port, baudrate=int(baud), bytesize=8,
            parity="N", stopbits=1, timeout=timeout,
        )
        self._read_kw = _unit_kwarg(self.client.read_holding_registers)
        self._write_kw = _unit_kwarg(self.client.write_register)
        self.address = int(address)
        ok = self.client.connect()
        if not ok:
            self.client = None
        return ok

    def connect_tcp(self, host, port, address, framer="socket", timeout=5):
        """Connect to sensor WiFi ASCII gateway on port 8888.

        Opens a raw TCP socket to port 8888 (firmware ASCII command interface).
        Reads use RX260/RX208 ASCII commands — proven reliable.
        Modbus/TCP on port 8502 was unreliable and dropped in firmware V2.0.
        Calibration writes still require a Serial connection.
        """
        self.disconnect()
        import socket as _socket
        self.mode = "tcp"
        self.address = int(address)
        ascii_port = 8888  # Always use the ASCII command port
        try:
            sock = _socket.socket(_socket.AF_INET, _socket.SOCK_STREAM)
            sock.settimeout(timeout)
            sock.connect((host, ascii_port))
            sock.settimeout(4)  # Per-command read timeout
            self._tcp_sock = sock
            print(f"[TCP-ASCII] Connected to {host}:{ascii_port}, address {address}")
            return True
        except Exception as e:
            print(f"[TCP-ASCII] Failed to connect to {host}:{ascii_port}: {e}")
            self._tcp_sock = None
            return False

    def disconnect(self):
        if self._tcp_sock is not None:
            try:
                self._tcp_sock.close()
            except Exception:
                pass
            self._tcp_sock = None
        if self.client is not None:
            try:
                self.client.close()
            except Exception:
                pass
        self.client = None

    def _ascii_cmd(self, cmd, timeout=4):
        """Send one ASCII command to port-8888 and return the stripped response line.
        Returns None on error or disconnect."""
        if self._tcp_sock is None:
            return None
        try:
            self._tcp_sock.settimeout(timeout)
            self._tcp_sock.sendall((cmd + "\n").encode())
            buf = b""
            while b"\n" not in buf:
                chunk = self._tcp_sock.recv(1024)
                if not chunk:
                    break
                buf += chunk
            line = buf.split(b"\n")[0].decode(errors="replace").strip()
            return line if line else None
        except Exception as e:
            print(f"[TCP-ASCII] {cmd!r} error: {e}")
            try:
                self._tcp_sock.close()
            except Exception:
                pass
            self._tcp_sock = None  # auto-disconnect on error
            return None

    # -- low level -------------------------------------------------
    def read(self, reg, count=1, address=None):
        """Read holding register(s). Returns list of raw ints or None on error."""
        if self.mode == "tcp":
            # TCP reads go through _ascii_cmd() / _tds_read_tcp(); not via Modbus
            print(f"[Modbus] read(reg={reg}) skipped — TCP mode uses ASCII commands")
            return None
        if self.client is None:
            print(f"[Modbus] Read failed: client is None")
            return None
        addr = self.address if address is None else int(address)
        kw = {self._read_kw: addr, "count": count}
        try:
            rr = self.client.read_holding_registers(reg, **kw)
        except TypeError:
            # older signature: count positional
            try:
                rr = self.client.read_holding_registers(reg, count, **{self._read_kw: addr})
            except Exception as e:
                print(f"[Modbus] Read exception (reg={reg}, count={count}, addr={addr}): {e}")
                return None
        except Exception as e:
            print(f"[Modbus] Read exception (reg={reg}, count={count}, addr={addr}): {e}")
            return None
        if rr is None or (hasattr(rr, "isError") and rr.isError()):
            err = str(rr) if rr else "No response"
            print(f"[Modbus] Read error (reg={reg}, count={count}, addr={addr}): {err}")
            return None
        return list(rr.registers)

    def write(self, reg, value, address=None):
        """Write single holding register. Returns True/False."""
        if self.mode == "tcp":
            print(f"[TCP] Write blocked (reg={reg}) — calibration requires Serial connection")
            return False
        if self.client is None:
            return False
        addr = self.address if address is None else int(address)
        kw = {self._write_kw: addr}
        try:
            wr = self.client.write_register(reg, int(value), **kw)
        except Exception:
            return False
        if wr is None or (hasattr(wr, "isError") and wr.isError()):
            return False
        return True


class ScpiLink:
    """Minimal thread-safe SCPI-over-TCP client used to talk to bench
    instruments (Mensor CPC6050 pressure controller, Keysight 34461A DMM).

    Each instrument gets its own independent socket - these are *separate*
    from the main sensor ModbusLink.  Standard SCPI LAN sockets listen on
    port 5025 and use newline-terminated ASCII commands; a trailing '?'
    denotes a query that returns one response line.
    """

    def __init__(self, name="SCPI"):
        self.name = name
        self.sock = None
        self.lock = threading.Lock()

    @property
    def connected(self):
        return self.sock is not None

    def connect(self, host, port=5025, timeout=4):
        self.close()
        import socket as _socket
        try:
            s = _socket.socket(_socket.AF_INET, _socket.SOCK_STREAM)
            s.settimeout(timeout)
            s.connect((host, int(port)))
            s.settimeout(timeout)
            self.sock = s
            print(f"[{self.name}] connected to {host}:{port}")
            return True
        except Exception as e:
            print(f"[{self.name}] connect failed {host}:{port}: {e}")
            self.sock = None
            return False

    def close(self):
        if self.sock is not None:
            try:
                self.sock.close()
            except Exception:
                pass
            self.sock = None

    def write(self, cmd, timeout=4):
        """Send a command with no expected reply. Returns True on success."""
        if self.sock is None:
            return False
        try:
            self.sock.settimeout(timeout)
            self.sock.sendall((cmd + "\n").encode())
            return True
        except Exception as e:
            print(f"[{self.name}] write {cmd!r} error: {e}")
            self.close()
            return False

    def query(self, cmd, timeout=4):
        """Send a query and return the stripped response line, or None."""
        if self.sock is None:
            return None
        try:
            self.sock.settimeout(timeout)
            self.sock.sendall((cmd + "\n").encode())
            buf = b""
            while b"\n" not in buf:
                chunk = self.sock.recv(1024)
                if not chunk:
                    break
                buf += chunk
            line = buf.split(b"\n")[0].decode(errors="replace").strip()
            return line if line else None
        except Exception as e:
            print(f"[{self.name}] query {cmd!r} error: {e}")
            self.close()
            return None

    def query_float(self, cmd, timeout=4):
        """Query and parse the first float in the reply (handles SCPI
        responses that may carry units or extra fields)."""
        raw = self.query(cmd, timeout=timeout)
        if raw is None:
            return None
        try:
            return float(raw.split(",")[0].split()[0])
        except Exception:
            try:
                import re as _re
                m = _re.search(r"[-+]?\d*\.?\d+(?:[eE][-+]?\d+)?", raw)
                return float(m.group()) if m else None
            except Exception:
                return None


def to_signed16(raw):
    return raw - 65536 if raw > 32767 else raw


